args.sparql:
SELECT ?president ?presidentLabel ?child ?childLabel WHERE {
  VALUES ?president { wd:Q6279 wd:Q22686 wd:Q76 }
  ?president wdt:P40 ?child .
  ?child rdfs:label ?childLabel .
  ?president rdfs:label ?presidentLabel .
  FILTER (LANG(?childLabel) = "en") .
  FILTER (LANG(?presidentLabel) = "en") .
}
ORDER BY ?president
